/** 內嵌用行內圖示（非 flex 容器如按鈕、分頁、標籤內用）。回傳 <span class="sfi">SVG</span> */
function sfInlineIcon(name) {
  return '<span class="sfi">' + (SF_ICONS[name] || "") + "</span>";
}

/** SF 側邊欄（新版視覺，URL 沿用既有路由） */
