              return '<div class="order-customer-opt" data-id="' + escAttr(id) + '" data-name="' + escAttr(name) + '" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid var(--notion-border);font-size:14px;">' + escHtml(name) + '</div>';
