        const scaleRaw = parseInt(String(req.query.scale ?? "2"), 10);
        const heightRaw = parseInt(String(req.query.height ?? "10"), 10);
        const scale = Number.isFinite(scaleRaw) ? Math.min(8, Math.max(1, scaleRaw)) : 2;
