                "FROM orders o LEFT JOIN complaint_handling ch ON ch.order_id = o.id " +
                "WHERE o.customer_id = ? AND LOWER(TRIM(COALESCE(o.status,''))) = 'complaint' " +
                "ORDER BY o.order_date DESC, o.id DESC LIMIT 30"
